"use strict";(self.webpackChunksysanalyst_kb=self.webpackChunksysanalyst_kb||[]).push([["44956"],{65684(s){s.exports=JSON.parse('{"tag":{"label":"edo","permalink":"/sysanalyst-kb.github.io/docs/tags/edo","allTagsPath":"/sysanalyst-kb.github.io/docs/tags","count":2,"items":[{"id":"specialization/govtech-edo","title":"\u042D\u0414\u041E \u0438 \u0434\u043E\u043A\u0443\u043C\u0435\u043D\u0442\u043E\u043E\u0431\u043E\u0440\u043E\u0442 \u0432 \u0433\u043E\u0441\u0441\u0435\u043A\u0442\u043E\u0440\u0435","description":"\u042D\u0414\u041E (\u044D\u043B\u0435\u043A\u0442\u0440\u043E\u043D\u043D\u044B\u0439 \u0434\u043E\u043A\u0443\u043C\u0435\u043D\u0442\u043E\u043E\u0431\u043E\u0440\u043E\u0442) \u0432 \u0433\u043E\u0441\u0441\u0435\u043A\u0442\u043E\u0440\u0435 \u2014 \u043D\u0435 \u043F\u0440\u043E\u0441\u0442\u043E \u043E\u0431\u043C\u0435\u043D \u0444\u0430\u0439\u043B\u0430\u043C\u0438. \u042D\u0442\u043E \u044E\u0440\u0438\u0434\u0438\u0447\u0435\u0441\u043A\u0438 \u0437\u043D\u0430\u0447\u0438\u043C\u044B\u0439 \u0434\u043E\u043A\u0443\u043C\u0435\u043D\u0442\u043E\u043E\u0431\u043E\u0440\u043E\u0442 \u0441 \u0423\u041A\u042D\u041F (\u0443\u0441\u0438\u043B\u0435\u043D\u043D\u043E\u0439 \u043A\u0432\u0430\u043B\u0438\u0444\u0438\u0446\u0438\u0440\u043E\u0432\u0430\u043D\u043D\u043E\u0439 \u044D\u043B\u0435\u043A\u0442\u0440\u043E\u043D\u043D\u043E\u0439 \u043F\u043E\u0434\u043F\u0438\u0441\u044C\u044E \u043F\u043E \u0413\u041E\u0421\u0422 \u0420 34.10), \u0421\u041C\u042D\u0412-\u0438\u043D\u0442\u0435\u0433\u0440\u0430\u0446\u0438\u0435\u0439, \u0430\u0440\u0445\u0438\u0432\u0438\u0440\u043E\u0432\u0430\u043D\u0438\u0435\u043C (5-75 \u043B\u0435\u0442) \u0438 \u0441\u0442\u0440\u043E\u0433\u0438\u043C\u0438 \u0441\u0440\u043E\u043A\u0430\u043C\u0438 \u043F\u043E 59-\u0424\u0417 (30 \u0434\u043D\u0435\u0439). \u0422\u0438\u043F\u044B Directum, TESSA, 1\u0421:\u0414\u043E\u043A\u0443\u043C\u0435\u043D\u0442\u043E\u043E\u0431\u043E\u0440\u043E\u0442, \xab\u0414\u0435\u043B\u043E\xbb. \u0410\u043D\u0430\u043B\u0438\u0442\u0438\u043A \u0441\u043F\u0435\u0446\u0438\u0444\u0438\u0446\u0438\u0440\u0443\u0435\u0442 \u043C\u0430\u0440\u0448\u0440\u0443\u0442\u044B \u0441\u043E\u0433\u043B\u0430\u0441\u043E\u0432\u0430\u043D\u0438\u044F (\u043F\u043E\u0441\u043B\u0435\u0434\u043E\u0432\u0430\u0442\u0435\u043B\u044C\u043D\u044B\u0435/\u043F\u0430\u0440\u0430\u043B\u043B\u0435\u043B\u044C\u043D\u044B\u0435), \u0444\u043E\u0440\u043C\u0430\u0442 \u0434\u043E\u043A\u0443\u043C\u0435\u043D\u0442\u043E\u0432 (PDF/A, XML \u0441 \u0423\u041A\u042D\u041F) \u0438 \u0438\u043D\u0442\u0435\u0433\u0440\u0430\u0446\u0438\u044E \u0441 \u0423\u0434\u043E\u0441\u0442\u043E\u0432\u0435\u0440\u044F\u044E\u0449\u0438\u043C \u0446\u0435\u043D\u0442\u0440\u043E\u043C.","permalink":"/sysanalyst-kb.github.io/docs/specialization/govtech-edo"},{"id":"specialization/logistics-edo","title":"\u042D\u0414\u041E \u0438 \u0434\u043E\u043A\u0443\u043C\u0435\u043D\u0442\u043E\u043E\u0431\u043E\u0440\u043E\u0442 \u0432 \u043B\u043E\u0433\u0438\u0441\u0442\u0438\u043A\u0435","description":"\u042D\u0414\u041E (\u044D\u043B\u0435\u043A\u0442\u0440\u043E\u043D\u043D\u044B\u0439 \u0434\u043E\u043A\u0443\u043C\u0435\u043D\u0442\u043E\u043E\u0431\u043E\u0440\u043E\u0442) \u0432 \u043B\u043E\u0433\u0438\u0441\u0442\u0438\u043A\u0435 \u2014 \u043E\u0431\u043C\u0435\u043D \u0423\u041F\u0414, \u0430\u043A\u0442\u0430\u043C\u0438, \u0441\u0447\u0435\u0442\u0430\u043C\u0438-\u0444\u0430\u043A\u0442\u0443\u0440\u0430\u043C\u0438, \u0442\u0440\u0430\u043D\u0441\u043F\u043E\u0440\u0442\u043D\u044B\u043C\u0438 \u043D\u0430\u043A\u043B\u0430\u0434\u043D\u044B\u043C\u0438 \u043C\u0435\u0436\u0434\u0443 \u0443\u0447\u0430\u0441\u0442\u043D\u0438\u043A\u0430\u043C\u0438 (\u0433\u0440\u0443\u0437\u043E\u043E\u0442\u043F\u0440\u0430\u0432\u0438\u0442\u0435\u043B\u044C, \u043F\u0435\u0440\u0435\u0432\u043E\u0437\u0447\u0438\u043A, \u0433\u0440\u0443\u0437\u043E\u043F\u043E\u043B\u0443\u0447\u0430\u0442\u0435\u043B\u044C). \u0421 2021 \u0433\u043E\u0434\u0430 \u042D\u0422\u0420\u041D (\u044D\u043B\u0435\u043A\u0442\u0440\u043E\u043D\u043D\u0430\u044F \u0442\u0440\u0430\u043D\u0441\u043F\u043E\u0440\u0442\u043D\u0430\u044F \u043D\u0430\u043A\u043B\u0430\u0434\u043D\u0430\u044F) \u043E\u0431\u044F\u0437\u0430\u0442\u0435\u043B\u044C\u043D\u0430 \u0434\u043B\u044F \u0433\u0440\u0443\u0437\u043E\u043F\u0435\u0440\u0435\u0432\u043E\u0437\u043E\u043A \u0432 \u0420\u0424. \u0423\u0447\u0430\u0441\u0442\u043D\u0438\u043A\u0438 \u043F\u043E\u0434\u043F\u0438\u0441\u044B\u0432\u0430\u044E\u0442 \u0434\u043E\u043A\u0443\u043C\u0435\u043D\u0442\u044B \u0423\u041A\u042D\u041F (\u0443\u0441\u0438\u043B\u0435\u043D\u043D\u0430\u044F \u043A\u0432\u0430\u043B\u0438\u0444\u0438\u0446\u0438\u0440\u043E\u0432\u0430\u043D\u043D\u0430\u044F \u044D\u043B\u0435\u043A\u0442\u0440\u043E\u043D\u043D\u0430\u044F \u043F\u043E\u0434\u043F\u0438\u0441\u044C) \u0447\u0435\u0440\u0435\u0437 \u043E\u043F\u0435\u0440\u0430\u0442\u043E\u0440\u043E\u0432 \u042D\u0414\u041E (\u0414\u0438\u0430\u0434\u043E\u043A, \u0421\u0411\u0418\u0421, \u041A\u043E\u043D\u0442\u0443\u0440). \u0410\u043D\u0430\u043B\u0438\u0442\u0438\u043A \u043F\u0440\u043E\u0435\u043A\u0442\u0438\u0440\u0443\u0435\u0442 \u0442\u0438\u043F\u044B \u0434\u043E\u043A\u0443\u043C\u0435\u043D\u0442\u043E\u0432, \u0441\u0442\u0430\u0442\u0443\u0441\u043D\u0443\u044E \u043C\u043E\u0434\u0435\u043B\u044C, \u0438\u043D\u0442\u0435\u0433\u0440\u0430\u0446\u0438\u044E \u0441 \u043E\u043F\u0435\u0440\u0430\u0442\u043E\u0440\u0430\u043C\u0438 \u0438 TMS.","permalink":"/sysanalyst-kb.github.io/docs/specialization/logistics-edo"}],"unlisted":false}}')}}]);